scriptContent:
# Chokepoint Ransomware Service Emulation
# Creates test services, bulk stop+disable+delete
# Expected Detections: EID 7036/7040 (service state changes)

[CmdletBinding()]
param(
    [switch]$DryRun
)

Write-Host "=== Chokepoint Ransomware Service Emulation ===" -ForegroundColor Cyan
Write-Host "Emulating ransomware service disruption techniques"

# Stage 1: Create test services
Write-Host "\n[Stage 1] Creating test services..."
$serviceNames = @("RansomTestSvc1", "RansomTestSvc2", "RansomTestSvc3")

foreach ($svcName in $serviceNames) {
    if (-not $DryRun) {
        try {
            sc.exe create $svcName binPath= "C:\Windows\System32\svchost.exe -k netsvcs" start= auto
            Write-Host "  Created: $svcName" -ForegroundColor Yellow
        } catch {
            Write-Host "  Error creating $svcName`: $($_.Exception.Message)" -ForegroundColor Red
        }
    } else {
        Write-Host "  [DryRun] Would create: $svcName" -ForegroundColor Magenta
    }
}

# Stage 2: Bulk stop services (WEL 7036 target)
Write-Host "\n[Stage 2] Stopping test services (bulk)..."
if (-not $DryRun) {
    foreach ($svcName in $serviceNames) {
        try {
            Stop-Service -Name $svcName -Force -ErrorAction SilentlyContinue
            Write-Host "  Stopped: $svcName" -ForegroundColor Yellow
        } catch {
            Write-Host "  Error stopping $svcName`: $($_.Exception.Message)" -ForegroundColor Red
        }
    }
    Write-Host "  Expected Detection: WEL 7036 (ServiceStateChange) x3" -ForegroundColor Cyan
} else {
    Write-Host "  [DryRun] Would stop all test services" -ForegroundColor Magenta
}

# Stage 3: Disable services (WEL 7040 target)
Write-Host "\n[Stage 3] Disabling test services..."
if (-not $DryRun) {
    foreach ($svcName in $serviceNames) {
        try {
            Set-Service -Name $svcName -StartupType Disabled -ErrorAction SilentlyContinue
            Write-Host "  Disabled: $svcName" -ForegroundColor Yellow
        } catch {
            Write-Host "  Error disabling $svcName`: $($_.Exception.Message)" -ForegroundColor Red
        }
    }
    Write-Host "  Expected Detection: WEL 7040 (ServiceConfigChange) x3" -ForegroundColor Cyan
} else {
    Write-Host "  [DryRun] Would disable all test services" -ForegroundColor Magenta
}

# Stage 4: Delete services
Write-Host "\n[Stage 4] Deleting test services..."
if (-not $DryRun) {
    foreach ($svcName in $serviceNames) {
        try {
            sc.exe delete $svcName
            Write-Host "  Deleted: $svcName" -ForegroundColor Yellow
        } catch {
            Write-Host "  Error deleting $svcName`: $($_.Exception.Message)" -ForegroundColor Red
        }
    }
} else {
    Write-Host "  [DryRun] Would delete all test services" -ForegroundColor Magenta
}

Write-Host "\n=== Emulation Complete ===" -ForegroundColor Cyan
Write-Host "Expected Detections:"
Write-Host "  - WEL 7036: Service state changes (stopped)" -ForegroundColor Green
Write-Host "  - WEL 7040: Service config changes (disabled)" -ForegroundColor Green
